INSERT INTO `mikrotik_script_templates` VALUES (1,'HOTSPOT ONLY','v7','# Generated by MikroTik Print Detail Converter UI v16\n# Support: multi menu path, print detail, setting tunggal, dan script/export block.\n# Script dibungkus :do agar variable tetap aman saat copy-paste ke terminal.\n:do {\n    # PILIH TARGET ROUTEROS DENGAN TOMBOL DI UI: Auto / ROS 6 / ROS 7\n    :local rbillTargetRos \"auto\"\n    :local rbillRosMajor 7\n    :if ($rbillTargetRos = \"auto\") do={\n        :do {\n            :local rbillRosVersion [/system resource get version]\n            :local rbillDotPos [:find $rbillRosVersion \".\"]\n            :if ($rbillDotPos > 0) do={ :set rbillRosMajor [:tonum [:pick $rbillRosVersion 0 $rbillDotPos]] }\n        } on-error={ :set rbillRosMajor 7 }\n    } else={ :set rbillRosMajor [:tonum $rbillTargetRos] }\n    :put (\"RBILL target RouterOS major: \" . $rbillRosMajor)\n\n    # --- Setting tunggal: /system identity ---\n    :do {\n        /system identity set name=\"#shortname#\"\n    } on-error={ :put \"skip/gagal command: /system identity set name=\'#shortname#\'\" }\n\n    # --- Setting tunggal: /system clock ---\n    :do {\n        /system clock set time=22:51:01 date=2026-05-28 time-zone-autodetect=no time-zone-name=Asia/Jakarta gmt-offset=+07:00 dst-active=no\n    } on-error={ :put \"skip/gagal command: /system clock set time=22:51:01 date=2026-05-28 time-zone-autodetect=no time-zone-name=Asia/Jakarta gmt-offset=+07:00 dst-active=no\" }\n\n    # --- Setting tunggal: /radius incoming ---\n    :do {\n        /radius incoming set accept=yes port=3799 vrf=main\n    } on-error={ :put \"skip/gagal command: /radius incoming set accept=yes port=3799 vrf=main\" }\n\n    # --- Script/export block: /ip dns ---\n    :do {\n        /ip dns set allow-remote-requests=yes\n    } on-error={ :put \"skip/gagal command: /ip dns set allow-remote-requests=yes\" }\n\n    # --- Script/export block: /system ntp client ---\n    :do {\n        /system ntp client set enabled=yes server=162.159.200.1,162.159.200.123\n    } on-error={ :put \"skip/gagal command: /system ntp client set enabled=yes server=162.159.200.1,162.159.200.123\" }\n\n    # --- Script/export block: /ip hotspot profile ---\n    :foreach rbillId in=[/ip hotspot profile find] do={\n        :do { /ip hotspot profile set $rbillId use-radius=yes radius-accounting=yes } on-error={ :put \"skip/gagal set: /ip hotspot profile set [find] use-radius=yes radius-accounting=yes\" }\n    }\n    :foreach rbillId in=[/ip hotspot profile find] do={\n        :do { /ip hotspot profile set $rbillId radius-interim-update=0s } on-error={ :put \"skip/gagal set: /ip hotspot profile set [find] radius-interim-update=0s\" }\n    }\n    :foreach rbillId in=[/ip hotspot profile find] do={\n        :do { /ip hotspot profile set $rbillId install-hotspot-queue=no } on-error={ :put \"skip/gagal set: /ip hotspot profile set [find] install-hotspot-queue=no\" }\n    }\n\n    # --- /radius comment=Radius Billing Direct ---\n    :foreach rbillId in=[/radius find where comment=\"Radius Billing Direct\"] do={\n        :do {\n            /radius remove $rbillId\n        } on-error={ :put \"gagal hapus item lama: comment=Radius Billing Direct\" }\n    }\n    :do {\n        /radius add service=ppp,hotspot called-id=\"\" domain=\"\" address=\"#server_ip#\" secret=\"#secret#\" authentication-port=\"#auth_port#\" accounting-port=\"#acct_port#\" timeout=300ms accounting-backup=no realm=\"\" protocol=udp certificate=none require-message-auth=no comment=\"Radius Billing Direct\"\n    } on-error={ :put \"gagal add / kemungkinan parameter beda versi: comment=Radius Billing Direct\" }\n\n    :put \"RBILL convert selesai.\"\n} on-error={ :put \"RBILL convert error. Cek command terakhir/parameter beda versi.\" }','#server_ip#,#nasname#,#secret#,#auth_port#,#acct_port#','Script RADIUS langsung via IP Publik MikroTik, cocok untuk koneksi direct tanpa VPN','2026-05-30 21:22:43','2026-05-31 00:03:49'),(2,'PPPOE ONLY','v7','