ip/gagal command: /system ntp client set enabled=yes server=162.159.200.1,162.159.200.123\" }\n\n    # --- /ip pool comment=ARMRAIDUS_Network : 10.200.192.0/20 ---\n    :foreach rbillId in=[/ip pool find where comment=\"ARMRAIDUS_Network : 10.200.192.0/20\"] do={\n        :do {\n            /ip pool remove $rbillId\n        } on-error={ :put \"gagal hapus item lama: comment=ARMRAIDUS_Network : 10.200.192.0/20\" }\n    }\n    :do {\n        /ip pool add name=ARMPOOL ranges=10.200.192.100-10.200.207.254 comment=\"ARMRAIDUS_Network : 10.200.192.0/20\"\n    } on-error={ :put \"gagal add / kemungkinan parameter beda versi: comment=ARMRAIDUS_Network : 10.200.192.0/20\" }\n\n    # --- /ip pool comment=ARMISOLIR_Network 10.200.208.0/23 ---\n    :foreach rbillId in=[/ip pool find where comment=\"ARMISOLIR_Network 10.200.208.0/23\"] do={\n        :do {\n            /ip pool remove $rbillId\n        } on-error={ :put \"gagal hapus item lama: comment=ARMISOLIR_Network 10.200.208.0/23\" }\n    }\n    :do {\n        /ip pool add name=ARMISOLIR ranges=10.200.208.10-10.200.209.254 comment=\"ARMISOLIR_Network 10.200.208.0/23\"\n    } on-error={ :put \"gagal add / kemungkinan parameter beda versi: comment=ARMISOLIR_Network 10.200.208.0/23\" }\n\n    # --- /ppp profile comment=default by rlradius (jangan dirubah ARMPOOL) ---\n    :foreach rbillId in=[/ppp profile find where comment=\"default by rlradius (jangan dirubah ARMPOOL)\"] do={\n        :do {\n            /ppp profile remove $rbillId\n        } on-error={ :put \"gagal hapus item lama: comment=default by rlradius (jangan dirubah ARMPOOL)\" }\n    }\n    :do {\n        /ppp profile add name=ARM_RADIUS local-address=10.200.192.1 remote-address=ARMPOOL bridge-learning=default use-ipv6=yes use-mpls=default use-compression=no use-encryption=no only-one=yes change-tcp-mss=yes use-upnp=default address-list=\"\" on-up=\"\" on-down=\"\" comment=\"default by rlradius (jangan dirubah ARMPOOL)\"\n    } on-error={ :put \"gagal add / kemungkinan parameter beda versi: comment=default by rlradius (jangan dirubah ARMPOOL)\" }\n\n    # --- /ppp profile comment=default by rlradius (jangan dirubah ARMISOLIR) ---\n    :foreach rbillId in=[/ppp profile find where comment=\"default by rlradius (jangan dirubah ARMISOLIR)\"] do={\n        :do {\n            /ppp profile remove $rbillId\n        } on-error={ :put \"gagal hapus item lama: comment=default by rlradius (jangan dirubah ARMISOLIR)\" }\n    }\n    :do {\n        /ppp profile add name=ARM_ISOLIR local-address=10.200.208.1 remote-address=ARMISOLIR bridge-learning=default use-ipv6=yes use-mpls=default use-compression=no use-encryption=no only-one=yes change-tcp-mss=yes use-upnp=default address-list=\"\" on-up=\"\" on-down=\"\" comment=\"default by rlradius (jangan dirubah ARMISOLIR)\"\n    } on-error={ :put \"gagal add / kemungkinan parameter beda versi: comment=default by rlradius (jangan dirubah ARMISOLIR)\" }\n\n    # --- /radius comment=Radius Billing Direct ---\n    :foreach rbillId in=[/radius find where comment=\"Radius Billing Direct\"] do={\n        :do {\n            /radius remove $rbillId\n        } on-error={ :put \"gagal hapus item lama: comment=Radius Billing Direct\" }\n    }\n    :do {\n        /radius add service=ppp,hotspot called-id=\"\" domain=\"\" address=\"#server_ip#\" secret=\"#secret#\" authentication-port=\"#auth_port#\" accounting-port=\"#acct_port#\" timeout=300ms accounting-backup=no realm=\"\" protocol=udp certificate=none require-message-auth=no comment=\"Radius Billing Direct\"\n    } on-error={ :put \"gagal add / kemungkinan parameter beda versi: comment=Radius Billing Direct\" }\n\n    :put \"RBILL convert selesai.\"\n} on-error={ :put \"RBILL convert error. Cek command terakhir/parameter beda versi.\" }','#server_ip#,#vpn_user#,#vpn_pass#,#vpn_psk#,#vpn_local_ip#,#secret#,#auth_port#,#acct_port#','Script RADIUS via VPN L2TP/IPsec untuk MikroTik RouterOS v7, cocok untuk MikroTik di jaringan NAT/private','2026-05-30 21:22:4